/**
 * Prisma Client singleton — the single module the app imports for DB access (`@/lib/db`).
 *
 * Global-cache pattern: in dev, Next.js hot-reload re-evaluates modules, which would spawn a new
 * PrismaClient (and a new connection pool) on every reload. Caching the instance on `globalThis`
 * keeps exactly one client per process. (In production we intentionally do NOT cache on global.)
 *
 * Prisma 7 notes:
 *  - The client is generated by the modern `prisma-client` generator into src/generated/prisma
 *    (gitignored; `postinstall`/`db:generate` recreate it), so we import `PrismaClient` from the
 *    generated path `@/generated/prisma/client`, not the legacy `@prisma/client` package entry.
 *  - The runtime connects through a driver adapter (here @prisma/adapter-pg over node-postgres),
 *    not a `url` in schema.prisma — Prisma 7 removed schema `url` (see prisma/schema.prisma and
 *    prisma.config.mjs). The adapter reads DATABASE_URL. Constructing the client does NOT open a
 *    connection, so importing this module is safe at build time; only a query touches the DB. Keep
 *    DB queries behind dynamic routes / server actions so `yarn build` never hits the database.
 *
 * Boundary convention (context/coding-standards.md): every route/action that uses `prisma` validates
 * its input with a zod schema via `validate()` (src/lib/validation.js) before reading/writing.
 */
import { PrismaClient } from "@/generated/prisma/client";
import { PrismaPg } from "@prisma/adapter-pg";

const globalForPrisma = globalThis;

const createPrismaClient = () =>
  new PrismaClient({
    adapter: new PrismaPg({ connectionString: process.env.DATABASE_URL }),
  });

export const prisma = globalForPrisma.prisma ?? createPrismaClient();

if (process.env.NODE_ENV !== "production") globalForPrisma.prisma = prisma;
